    addChoice(params::clipperMode,"Peak Style",{"Soft","Firm"});addChoice(params::limiterStyle,"Limit Style",{"Transparent","Punch"});addChoice(params::analyzerMode,"Spectrum",{"Input","Output","Both"});startTimerHz(20);
