AuroraBroadcastProcessorEditor::~AuroraBroadcastProcessorEditor(){processor.engine().setAnalyzerConsumerActive(false);processor.parameters.state.setProperty("editorWidth",getWidth(),nullptr);processor.parameters.state.setProperty("editorHeight",getHeight(),nullptr);setLookAndFeel(nullptr);}
void AuroraBroadcastProcessorEditor::addKnob(const char* id,const juce::String& n,const juce::String& t){auto c=std::make_unique<KnobControl>(processor.parameters,id,n,t);controlContent.addAndMakeVisible(*c);knobs.push_back(std::move(c));}void AuroraBroadcastProcessorEditor::addToggle(const char* id,const juce::String& n,const juce::String& t){auto c=std::make_unique<ToggleControl>(processor.parameters,id,n,t);controlContent.addAndMakeVisible(*c);toggles.push_back(std::move(c));}void AuroraBroadcastProcessorEditor::addChoice(const char* id,const juce::String& n,juce::StringArray a){auto c=std::make_unique<ChoiceControl>(processor.parameters,id,n,a);controlContent.addAndMakeVisible(*c);choices.push_back(std::move(c));}
void AuroraBroadcastProcessorEditor::paint(juce::Graphics& g){g.fillAll(colours::background);g.setColour(colours::grid);g.drawHorizontalLine(48,0,static_cast<float>(getWidth()));}
void AuroraBroadcastProcessorEditor::resized(){processor.parameters.state.setProperty("editorWidth",getWidth(),nullptr);processor.parameters.state.setProperty("editorHeight",getHeight(),nullptr);auto area=getLocalBounds().reduced(8);auto header=area.removeFromTop(40);title.setBounds(header.removeFromLeft(215));presetLabel.setBounds(header.removeFromLeft(40));previous.setBounds(header.removeFromLeft(24).reduced(2));next.setBounds(header.removeFromLeft(24).reduced(2));presetBox.setBounds(header.removeFromLeft(140).reduced(2));for(auto* b:{&save,&saveAs,&aButton,&bButton,&aToB,&bToA,&reset})b->setBounds(header.removeFromLeft(b==&saveAs?54:(b==&aButton||b==&bButton?30:44)).reduced(2));info.setBounds(header.removeFromRight(30).reduced(2));bypass.setBounds(header.removeFromRight(64));advanced.setBounds(header.removeFromRight(68).reduced(2));auto footerArea=area.removeFromBottom(24);footer.setBounds(footerArea);auto upper=advancedMode?area.removeFromTop(juce::jmax(220,static_cast<int>(area.getHeight()*0.52f))):area;meterDisplay.setBounds(upper.removeFromRight(100).reduced(4));spectrum.setBounds(upper.reduced(4));viewport.setBounds(area.reduced(0,4));const int cols=juce::jmax(6,getWidth()/112),cellW=110,knobH=104;int index=0;for(auto& k:knobs){const int row=index/cols,col=index%cols;k->setBounds(col*cellW,row*knobH,cellW,knobH);++index;}int y=((index+cols-1)/cols)*knobH+6;for(auto& t:toggles){const int col=(index++)%cols;if(col==0&&index>1)y+=30;t->setBounds(col*cellW,y,cellW,28);}y+=42;int ci=0;for(auto& c:choices){c->setBounds(ci++*160,y,156,52);}controlContent.setSize(cols*cellW,y+58);}
void AuroraBroadcastProcessorEditor::timerCallback(){meterDisplay.repaint();footer.setText("SR "+juce::String(processor.getSampleRate(),0)+" Hz   BLOCK "+juce::String(processor.currentBlockSize())+"   LATENCY "+juce::String(processor.getLatencySamples())+" samples   v"+config::version,juce::dontSendNotification);}
void AuroraBroadcastProcessorEditor::selectRelativePreset(int delta){auto i=(presetBox.getSelectedItemIndex()+delta+processor.getNumPrograms())%processor.getNumPrograms();presetBox.setSelectedItemIndex(i,juce::sendNotificationSync);}
void AuroraBroadcastProcessorEditor::savePreset(){juce::String error;auto name="User "+juce::Time::getCurrentTime().formatted("%Y%m%d-%H%M%S");if(!processor.presets.saveUser(name,error))juce::AlertWindow::showMessageBoxAsync(juce::MessageBoxIconType::WarningIcon,"Preset save failed",error);}
void AuroraBroadcastProcessorEditor::saveAsPreset(){fileChooser=std::make_unique<juce::FileChooser>("Export Aurora preset",juce::File::getSpecialLocation(juce::File::userDocumentsDirectory).getChildFile("AuroraPreset.aurorapreset"),"*.aurorapreset");fileChooser->launchAsync(juce::FileBrowserComponent::saveMode|juce::FileBrowserComponent::canSelectFiles|juce::FileBrowserComponent::warnAboutOverwriting,[this](const juce::FileChooser& chooser){auto f=chooser.getResult();if(f!=juce::File{}){juce::String error;if(!processor.presets.exportPreset(f,error))juce::AlertWindow::showMessageBoxAsync(juce::MessageBoxIconType::WarningIcon,"Preset export failed",error);}fileChooser.reset();});}
